import random,sys
from collections import deque
sys.setrecursionlimit(1000000)

def ref(g):
    N=len(g)
    R=[[4 if v==0 else 3 for v in r] for r in g]  # 0->4(enclosed default),3 stays
    # flood border-reachable 0s (value 4) back to 0
    from collections import deque
    q=deque()
    seen=[[False]*N for _ in range(N)]
    for i in range(N):
        for (a,b) in [(0,i),(N-1,i),(i,0),(i,N-1)]:
            if R[a][b]==4 and not seen[a][b]:
                seen[a][b]=True;q.append((a,b))
    while q:
        i,j=q.popleft();R[i][j]=0
        for a,b in [(i+1,j),(i-1,j),(i,j+1),(i,j-1)]:
            if 0<=a<N>b>=0 and R[a][b]==4 and not seen[a][b]:
                seen[a][b]=True;q.append((a,b))
    return R

def load(mod):
    ns={};exec(open(f'workdir/{mod}.py').read(),ns);return ns['p']

def rnd(N):
    return [[3 if random.random()<0.3 else 0 for _ in range(N)] for _ in range(N)]

